// MARK: - Models

enum TransactionType: String, Codable {
    case deposit
    case withdrawal
    case transfer
    case payment
}

enum TransactionStatus: String, Codable {
    case pending
    case completed
    case failed
    case cancelled
}

enum Currency: String, Codable {
    case usd = "USD"
    case eur = "EUR"
    case gbp = "GBP"
}

struct Transaction: Codable, Identifiable {
    let id: UUID
    let type: TransactionType
    let amount: Decimal
    let currency: Currency
    let fromAccountId: String
    let toAccountId: String?
    let description: String
    let timestamp: Date
    var status: TransactionStatus
    let referenceNumber: String
    
    init(type: TransactionType, amount: Decimal, currency: Currency, fromAccountId: String, toAccountId: String? = nil, description: String) {
        self.id = UUID()
        self.type = type
        self.amount = amount
        self.currency = currency
        self.fromAccountId = fromAccountId
        self.toAccountId = toAccountId
        self.description = description
        self.timestamp = Date()
        self.status = .pending
        self.referenceNumber = Self.generateReferenceNumber()
    }
    
    private static func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        let random = Int.random(in: 1000...9999)
        return "TXN-\(timestamp)-\(random)"
    }
}

struct Account: Codable, Identifiable {
    let id: String
    let accountNumber: String
    let accountHolderName: String
    var balance: Decimal
    let currency: Currency
    let createdAt: Date
    var isActive: Bool
    var transactions: [Transaction]
    
    var maskedAccountNumber: String {
        let suffix = String(accountNumber.suffix(4))
        return "****\(suffix)"
    }
}

struct TransactionResult {
    let success: Bool
    let transaction: Transaction
    let message: String
    let updatedBalance: Decimal?
}

// MARK: - Encryption Service

final class EncryptionService {
    
    static let shared = EncryptionService()
    
    private let keychainService = "com.bankingapp.encryption"
    private let symmetricKeyTag = "com.bankingapp.symmetrickey"
    
    private init() {
        _ = getOrCreateSymmetricKey()
    }
    
    // MARK: - Symmetric Key Management
    
    private func getOrCreateSymmetricKey() -> SymmetricKey {
        if let existingKeyData = loadKeyFromKeychain(tag: symmetricKeyTag) {
            return SymmetricKey(data: existingKeyData)
        }
        
        let newKey = SymmetricKey(size: .bits256)
        let keyData = newKey.withUnsafeBytes { Data($0) }
        saveKeyToKeychain(tag: symmetricKeyTag, data: keyData)
        return newKey
    }
    
    private func saveKeyToKeychain(tag: String, data: Data) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: tag,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        
        if status != errSecSuccess {
            print("Failed to save key to keychain: \(status)")
        }
    }
    
    private func loadKeyFromKeychain(tag: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: tag,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
    
    // MARK: - Encryption / Decryption
    
    func encrypt(data: Data) throws -> Data {
        let key = getOrCreateSymmetricKey()
        let sealedBox = try AES.GCM.seal(data, using: key)
        guard let combined = sealedBox.combined else {
            throw EncryptionError.encryptionFailed
        }
        return combined
    }
    
    func decrypt(data: Data) throws -> Data {
        let key = getOrCreateSymmetricKey()
        let sealedBox = try AES.GCM.SealedBox(combined: data)
        return try AES.GCM.open(sealedBox, using: key)
    }
    
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw EncryptionError.invalidInput
        }
        return try encrypt(data: data)
    }
    
    func decryptToString(data: Data) throws -> String {
        let decryptedData = try decrypt(data: data)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw EncryptionError.decryptionFailed
        }
        return string
    }
    
    // MARK: - Hashing
    
    func hashData(_ data: Data) -> String {
        let digest = SHA256.hash(data: data)
        return digest.map { String(format: "%02x", $0) }.joined()
    }
    
    func hashString(_ string: String) -> String {
        guard let data = string.data(using: .utf8) else { return "" }
        return hashData(data)
    }
    
    // MARK: - HMAC for Transaction Integrity
    
    func generateHMAC(for data: Data) -> Data {
        let key = getOrCreateSymmetricKey()
        let hmac = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(hmac)
    }
    
    func verifyHMAC(_ hmac: Data, for data: Data) -> Bool {
        let key = getOrCreateSymmetricKey()
        return HMAC<SHA256>.isValidAuthenticationCode(hmac, authenticating: data, using: key)
    }
}

enum EncryptionError: Error, LocalizedError {
    case encryptionFailed
    case decryptionFailed
    case invalidInput
    case keyGenerationFailed
    
    var errorDescription: String? {
        switch self {
        case .encryptionFailed: return "Failed to encrypt data"
        case .decryptionFailed: return "Failed to decrypt data"
        case .invalidInput: return "Invalid input data"
        case .keyGenerationFailed: return "Failed to generate encryption key"
        }
    }
}

// MARK: - Secure Storage

final class SecureStorageService {
    
    static let shared = SecureStorageService()
    
    private let encryption = EncryptionService.shared
    private let fileManager = FileManager.default
    
    private var storageURL: URL {
        let documentsPath = fileManager.urls(for: .documentDirectory, in: .userDomainMask).first!
        return documentsPath.appendingPathComponent("secure_banking_data")
    }
    
    private init() {
        createStorageDirectoryIfNeeded()
    }
    
    private func createStorageDirectoryIfNeeded() {
        if !fileManager.fileExists(atPath: storageURL.path) {
            try? fileManager.createDirectory(at: storageURL, withIntermediateDirectories: true)
        }
    }
    
    func saveEncrypted<T: Encodable>(_ object: T, forKey key: String) throws {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(object)
        let encryptedData = try encryption.encrypt(data: data)
        let fileURL = storageURL.appendingPathComponent(encryption.hashString(key))
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func loadEncrypted<T: Decodable>(_ type: T.Type, forKey key: String) throws -> T {
        let fileURL = storageURL.appendingPathComponent(encryption.hashString(key))
        let encryptedData = try Data(contentsOf: fileURL)
        let decryptedData = try encryption.decrypt(data: encryptedData)
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(type, from: decryptedData)
    }
    
    func deleteEncrypted(forKey key: String) {
        let fileURL = storageURL.appendingPathComponent(encryption.hashString(key))
        try? fileManager.removeItem(at: fileURL)
    }
    
    func exists(forKey key: String) -> Bool {
        let fileURL = storageURL.appendingPathComponent(encryption.hashString(key))
        return fileManager.fileExists(atPath: fileURL.path)
    }
}

// MARK: - Transaction Validator

final class TransactionValidator {
    
    enum ValidationError: Error, LocalizedError {
        case insufficientFunds(available: Decimal, requested: Decimal)
        case invalidAmount
        case accountInactive
        case sameAccountTransfer
        case dailyLimitExceeded(limit: Decimal)
        case invalidAccount
        case suspiciousActivity
        
        var errorDescription: String? {
            switch self {
            case .insufficientFunds(let available, let requested):
                return "Insufficient funds. Available: \(available), Requested: \(requested)"
            case .invalidAmount:
                return "Transaction amount must be greater than zero"
            case .accountInactive:
                return "Account is inactive"
            case .sameAccountTransfer:
                return "Cannot transfer to the same account"
            case .dailyLimitExceeded(let limit):
                return "Daily transaction limit of \(limit) exceeded"
            case .invalidAccount:
                return "Invalid account"
            case .suspiciousActivity:
                return "Transaction flagged for suspicious activity"
            }
        }
    }
    
    private let dailyTransactionLimit: Decimal = 50000.00
    private let maxSingleTransaction: Decimal = 25000.00
    
    func validate(transaction: Transaction, account: Account, allAccounts: [Account]) throws {
        guard account.isActive else {
            throw ValidationError.accountInactive
        }
        
        guard transaction.amount > 0 else {
            throw ValidationError.invalidAmount
        }
        
        guard transaction.amount <= maxSingleTransaction else {
            throw ValidationError.suspiciousActivity
        }
        
        switch transaction.type {
        case .withdrawal, .payment:
            guard account.balance >= transaction.amount else {
                throw ValidationError.insufficientFunds(available: account.balance, requested: transaction.amount)
            }
            
        case .transfer:
            guard account.balance >= transaction.amount else {
                throw ValidationError.insufficientFunds(available: account.balance, requested: transaction.amount)
            }
            guard let toAccountId = transaction.toAccountId else {
                throw ValidationError.invalidAccount
            }
            guard toAccountId != transaction.fromAccountId else {
                throw ValidationError.sameAccountTransfer
            }
            guard allAccounts.contains(where: { $0.id == toAccountId && $0.isActive }) else {
                throw ValidationError.invalidAccount
            }
            
        case .deposit:
            break
        }
        
        let todayTransactions = account.transactions.filter {
            Calendar.current.isDateInToday($0.timestamp) &&
            $0.status == .completed &&
            ($0.type == .withdrawal || $0.type == .transfer || $0.type == .payment)
        }
        let todayTotal = todayTransactions.reduce(Decimal.zero) { $0 + $1.amount }
        guard todayTotal + transaction.amount <= dailyTransactionLimit else {
            throw ValidationError.dailyLimitExceeded(limit: dailyTransactionLimit)
        }
    }
}

// MARK: - Audit Logger

final class AuditLogger {
    
    struct AuditEntry: Codable {
        let id: UUID
        let timestamp: Date
        let action: String
        let accountId: String
        let transactionId: String?
        let details: String
        let ipAddress: String?
        let deviceInfo: String
    }
    
    static let shared = AuditLogger()
    
    private let storage = SecureStorageService.shared
    private let storageKey = "audit_log"
    private var entries: [AuditEntry] = []
    private let queue = DispatchQueue(label: "com.bankingapp.auditlogger", qos: .utility)
    
    private init() {
        loadEntries()
    }
    
    private func loadEntries() {
        queue.sync {
            entries = (try? storage.loadEncrypted([AuditEntry].self, forKey: storageKey)) ?? []
        }
    }
    
    func log(action: String, accountId: String, transactionId: String? = nil, details: String) {
        queue.async { [weak self] in
            guard let self = self else { return }
            
            let entry = AuditEntry(
                id: UUID(),
                timestamp: Date(),
                action: action,
                accountId: accountId,
                transactionId: transactionId,
                details: details,
                ipAddress: nil,
                deviceInfo: self.getDeviceInfo()
            )
            
            self.entries.append(entry)
            try? self.storage.saveEncrypted(self.entries, forKey: self.storageKey)
        }
    }
    
    func getEntries(forAccountId accountId: String) -> [AuditEntry] {
        return queue.sync {
            entries.filter { $0.accountId == accountId }
        }
    }
    
    private func getDeviceInfo() -> String {
        #if os(iOS)
        return "iOS \(ProcessInfo.processInfo.operatingSystemVersionString)"
        #else
        return "Unknown"
        #endif
    }
}

// MARK: - Transaction Processing Engine

final class TransactionProcessor {
    
    static let shared = TransactionProcessor()
    
    private let validator = TransactionValidator()
    private let storage = SecureStorageService.shared
    private let encryption = EncryptionService.shared
    private let auditLogger = AuditLogger.shared
    private let accountsKey = "bank_accounts"
    private let processingQueue = DispatchQueue(label: "com.bankingapp.transactionprocessor", qos: .userInitiated)
    
    private var accounts: [Account] = []
    
    private init() {
        loadAccounts()
    }
    
    // MARK: - Account Management
    
    private func loadAccounts() {
        processingQueue.sync {
            accounts = (try? storage.loadEncrypted([Account].self, forKey: accountsKey)) ?? []
        }
    }
    
    private func saveAccounts() {
        try? storage.saveEncrypted(accounts, forKey: accountsKey)
    }
    
    func createAccount(holderName: String, initialBalance: Decimal, currency: Currency) -> Account {
        return processingQueue.sync {
            let accountNumber = generateAccountNumber()
            let account = Account(
                id: UUID().uuidString,
                accountNumber: accountNumber,
                accountHolderName: holderName,
                balance: initialBalance,
                currency: currency,
                createdAt: Date(),
                isActive: true,
                transactions: []
            )
            accounts.append(account)
            saveAccounts()
            
            auditLogger.log(
                action: "ACCOUNT_CREATED",
                accountId: account.id,
                details: "Account created with initial balance: \(initialBalance) \(currency.rawValue)"
            )
            
            return account
        }
    }
    
    func getAccount(byId id: String) -> Account? {
        return processingQueue.sync {
            accounts.first { $0.id == id }
        }
    }
    
    func getAllAccounts() -> [Account] {
        return processingQueue.sync {
            accounts
        }
    }
    
    func getBalance(forAccountId accountId: String) -> Decimal? {
        return processingQueue.sync {
            accounts.first { $0.id == accountId }?.balance
        }
    }
    
    private func generateAccountNumber() -> String {
        let digits = (0..<10).map { _ in String(Int.random(in: 0...9)) }.joined()
        return digits
    }
    
    // MARK: - Transaction Processing
    
    func processTransaction(_ transaction: Transaction, completion: @escaping (Result<TransactionResult, Error>) -> Void) {
        processingQueue.async { [weak self] in
            guard let self = self else { return }
            
            guard let accountIndex = self.accounts.firstIndex(where: { $0.id == transaction.fromAccountId }) else {
                let result = TransactionResult(
                    success: false,
                    transaction: transaction,
                    message: "Account not found",
                    updatedBalance: nil
                )
                DispatchQueue.main.async { completion(.success(result)) }
                return
            }
            
            do {
                try self.validator.validate(
                    transaction: transaction,
                    account: self.accounts[accountIndex],
                    allAccounts: self.accounts
                )
            } catch {
                var failedTransaction = transaction
                failedTransaction.status = .failed
                self.accounts[accountIndex].transactions.append(failedTransaction)
                self.saveAccounts()
                
                self.auditLogger.log(
                    action: "TRANSACTION_FAILED",
                    accountId: transaction.fromAccountId,
                    transactionId: transaction.id.uuidString,
                    details: "Validation failed: \(error.localizedDescription)"
                )
                
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }
            
            // Verify transaction integrity
            let transactionData = try? JSONEncoder().encode(transaction)
            if let data = transactionData {
                let hmac = self.encryption.generateHMAC(for: data)
                guard self.encryption.verifyHMAC(hmac, for: data) else {
                    DispatchQueue.main.async {
                        completion(.failure(EncryptionError.encryptionFailed))
                    }
                    return
                }
            }
            
            var completedTransaction = transaction
            completedTransaction.status = .completed
            
            switch transaction.type {
            case .deposit:
                self.accounts[accountIndex].balance += transaction.amount
                self.accounts[accountIndex].transactions.append(completedTransaction)
                
            case .withdrawal:
                self.accounts[accountIndex].balance -= transaction.amount
                self.accounts[accountIndex].transactions.append(completedTransaction)
                
            case .payment:
                self.accounts[accountIndex].balance -= transaction.amount
                self.accounts[accountIndex].transactions.append(completedTransaction)
                
            case .transfer:
                self.accounts[accountIndex].balance -= transaction.amount
                self.accounts[accountIndex].transactions.append(completedTransaction)
                
                if let toAccountId = transaction.toAccountId,
                   let toIndex = self.accounts.firstIndex(where: { $0.id == toAccountId }) {
                    self.accounts[toIndex].balance += transaction.amount
                    
                    let receivingTransaction = Transaction(
                        type: .deposit,
                        amount: transaction.amount,
                        currency: transaction.currency,
                        fromAccountId: toAccountId,
                        toAccountId: transaction.fromAccountId,
                        description: "Transfer from \(self.accounts[accountIndex].maskedAccountNumber)"
                    )
                    var completedReceiving = receivingTransaction
                    completedReceiving.status = .completed
                    self.accounts[toIndex].transactions.append(completedReceiving)
                }
            }
            
            self.saveAccounts()
            
            let updatedBalance = self.accounts[accountIndex].balance
            
            self.auditLogger.log(
                action: "TRANSACTION_COMPLETED",
                accountId: transaction.fromAccountId,
                transactionId: transaction.id.uuidString,
                details: "\(transaction.type.rawValue): \(transaction.amount) \(transaction.currency.rawValue). New balance: \(updatedBalance)"
            )
            
            let result = TransactionResult(
                success: true,
                transaction: completedTransaction,
                message: "Transaction completed successfully",
                updatedBalance: updatedBalance
            )
            
            DispatchQueue.main.async { completion(.success(result)) }
        }
    }
    
    func processTransactionAsync(_ transaction: Transaction) async throws -> TransactionResult {
        return try await withCheckedThrowingContinuation { continuation in
            processTransaction(transaction) { result in
                switch result {
                case .success(let transactionResult):
                    if transactionResult.success {
                        continuation.resume(returning: transactionResult)
                    } else {
                        continuation.resume(throwing: TransactionValidator.ValidationError.invalidAccount)
                    }
                case .failure(let error):
                    continuation.resume(throwing: error)
                }
            }
        }
    }
    
    // MARK: - Transaction History
    
    func getTransactionHistory(forAccountId accountId: String, limit: Int? = nil) -> [Transaction] {
        return processingQueue.sync {
            guard let account = accounts.first(where: { $0.id == accountId }) else {
                return []
            }
            let sorted = account.transactions.sorted { $0.timestamp > $1.timestamp }
            if let limit = limit {
                return Array(sorted.prefix(limit))
            }
            return sorted
        }
    }
    
    func getTransactionsByDateRange(accountId: String, from: Date, to: Date) -> [Transaction] {
        return processingQueue.sync {
            guard let account = accounts.first(where: { $0.id == accountId }) else {
                return []
            }
            return account.transactions.filter {
                $0.timestamp >= from && $0.timestamp <= to
            }.sorted { $0.timestamp > $1.timestamp }
        }
    }
}

// MARK: - Account Balance View Model

import SwiftUI

@MainActor
final class AccountBalanceViewModel: ObservableObject {
    
    @Published var accounts: [Account] = []
    @Published var selectedAccount: Account?
    @Published var transactions: [Transaction] = []
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    @Published var successMessage: String?
    @Published var totalBalance: Decimal = 0
    
    private let processor = TransactionProcessor.shared
    
    init() {
        loadAccounts()
    }
    
    func loadAccounts() {
        isLoading = true
        accounts = processor.getAllAccounts()
        totalBalance = accounts.reduce(Decimal.zero) { $0 + $1.balance }
        
        if let first = accounts.first {
            selectAccount(first)
        }
        isLoading = false
    }
    
    func selectAccount(_ account: Account) {
        selectedAccount = account
        transactions = processor.getTransactionHistory(forAccountId: account.id)
    }
    
    func createDemoAccount() {
        let account = processor.createAccount(
            holderName: "John Doe",
            initialBalance: 10000.00,
            currency: .usd
        )
        accounts.append(account)
        totalBalance = accounts.reduce(Decimal.zero) { $0 + $1.balance }
        selectAccount(account)
    }
    
    func deposit(amount: Decimal, description: String) {
        guard let account = selectedAccount else {
            errorMessage = "No account selected"
            return
        }
        
        let transaction = Transaction(
            type: .deposit,
            amount: amount,
            currency: account.currency,
            fromAccountId: account.id,
            description: description
        )
        
        isLoading = true
        errorMessage = nil
        successMessage = nil
        
        processor.processTransaction(transaction) { [weak self] result in
            self?.isLoading = false
            switch result {
            case .success(let txResult):
                if txResult.success {
                    self?.successMessage = "Deposit of \(amount) completed"
                    self?.loadAccounts()
                } else {
                    self?.errorMessage = txResult.message
                }
            case .failure(let error):
                self?.errorMessage = error.localizedDescription
            }
        }
    }
    
    func withdraw(amount: Decimal, description: String) {
        guard let account = selectedAccount else {
            errorMessage = "No account selected"
            return
        }
        
        let transaction = Transaction(
            type: .withdrawal,
            amount: amount,
            currency: account.currency,
            fromAccountId: account.id,
            description: description
        )
        
        isLoading = true
        errorMessage = nil
        successMessage = nil
        
        processor.processTransaction(transaction) { [weak self] result in
            self?.isLoading = false
            switch result {
            case .success(let txResult):
                if txResult.success {
                    self?.successMessage = "Withdrawal of \(amount) completed"
                    self?.loadAccounts()
                } else {
                    self?.errorMessage = txResult.message
                }
            case .failure(let error):
                self?.errorMessage = error.localizedDescription
            }
        }
    }
    
    func transfer(amount: Decimal, toAccountId: String, description: String) {
        guard let account = selectedAccount else {
            errorMessage = "No account selected"
            return
        }
        
        let transaction = Transaction(
            type: .transfer,
            amount: amount,
            currency: account.currency,
            fromAccountId: account.id,
            toAccountId: toAccountId,
            description: description
        )
        
        isLoading = true
        errorMessage = nil
        successMessage = nil
        
        processor.processTransaction(transaction) { [weak self] result in
            self?.isLoading = false
            switch result {
            case .success(let txResult):
                if txResult.success {
                    self?.successMessage = "Transfer of \(amount) completed"
                    self?.loadAccounts()
                } else {
                    self?.errorMessage = txResult.message
                }
            case .failure(let error):
                self?.errorMessage = error.localizedDescription
            }
        }
    }
}

