        .shadow(color: .blue.opacity(0.3), radius: 10, x: 0, y: 5)
    }
    
    private var emptyStateView: some View {
        VStack(spacing: 16) {
            Image(systemName: "banknote")
                .font(.system(size: 50))
                .foregroundColor(.gray)
            Text("No Accounts Yet")
                .font(.headline)
                .foregroundColor(.gray)
            Text("Tap + to create a demo account")
                .font(.subheadline)
                .foregroundColor(.gray.opacity(0.8))
        }
        .padding(40)
    }
    
    private var accountCardsSection: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text("Accounts")
                .font(.headline)
            
            ForEach(viewModel.accounts) { account in
                AccountCardView(
                    account: account,
                    isSelected: viewModel.selectedAccount?.id == account.id
                )
                .onTapGesture {
                    viewModel.selectAccount(account)
                }
            }
        }
    }
    
    private var transactionHistorySection: some View {
        VStack(alignment: .leading, spacing: 12) {
            HStack {
                Text("Recent Transactions")
                    .font(.headline)
                Spacer()
                Text("\(viewModel.transactions.count) total")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
            
            if viewModel.transactions.isEmpty {
                Text("No transactions yet")
                    .font(.subheadline)
                    .foregroundColor(.gray)
                    .padding()
                    .frame(maxWidth: .infinity)
            } else {
                ForEach(viewModel.transactions.prefix(10)) { transaction in
                    TransactionRowView(transaction: transaction)
                }
            }
        }
    }
    
    private var quickActionsSection: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text("Quick Actions")
                .font(.headline)
            
            HStack(spacing: 16) {
                quickActionButton(title: "Deposit", icon: "arrow.down.circle.fill", color: .green) {
                    selectedTransactionType = .deposit
                    showingTransactionSheet = true
                }
                quickActionButton(title: "Withdraw", icon: "arrow.up.circle.fill", color: .red) {
                    selectedTransactionType = .withdrawal
                    showingTransactionSheet = true
                }
                quickActionButton(title: "Transfer", icon: "arrow.left.arrow.right.circle.fill", color: .blue) {
                    selectedTransactionType = .transfer
                    showingTransactionSheet = true
                }
                quickActionButton(title: "Pay", icon: "creditcard.fill", color: .orange) {
                    selectedTransactionType = .payment
                    showingTransactionSheet = true
                }
            }
        }
    }
    
    private func quickActionButton(title: String, icon: String, color: Color, action: @escaping () -> Void) -> some View {
        Button(action: action) {
            VStack(spacing: 8) {
                Image(systemName: icon)
                    .font(.title2)
                    .foregroundColor(color)
                Text(title)
                    .font(.caption)
                    .foregroundColor(.primary)
            }
            .frame(maxWidth: .infinity)
            .padding(.vertical, 16)
            .background(Color(.systemGray6))
            .cornerRadius(12)
        }
    }
    
    private func messageView(text: String, isError: Bool) -> some View {
        HStack {
            Image(systemName: isError ? "exclamationmark.triangle.fill" : "checkmark.circle.fill")
            Text(text)
                .font(.subheadline)
        }
        .foregroundColor(isError ? .red : .green)
        .padding()
        .frame(maxWidth: .infinity, alignment: .leading)
        .background((isError ? Color.red : Color.green).opacity(0.1))
        .cornerRadius(10)
    }
    
    private func formatCurrency(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: amount as NSDecimalNumber) ?? "$0.00"
    }
}

struct AccountCardView: View {
    let account: Account
    let isSelected: Bool
    
    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack {
                VStack(alignment: .leading, spacing: 4) {
                    Text(account.accountHolderName)
                        .font(.subheadline)
                        .fontWeight(.medium)
                    Text(account.maskedAccountNumber)
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Spacer()
                VStack(alignment: .trailing, spacing: 4) {
                    Text(formatCurrency(account.balance, currency: account.currency))
                        .font(.headline)
                        .fontWeight(.bold)
                    Text(account.currency.rawValue)
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            
            HStack {
                Circle()
                    .fill(account.isActive ? Color.green : Color.red)
                    .frame(width: 8, height: 8)
                Text(account.isActive ? "Active" : "Inactive")
                    .font(.caption2)
                    .foregroundColor(.secondary)
                Spacer()
                Text("\(account.transactions.count) transactions")
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
        }
        .padding()
        .background(isSelected ? Color.blue.opacity(0.05) : Color(.systemGray6))
        .cornerRadius(12)
        .overlay(
            RoundedRectangle(cornerRadius: 12)
                .stroke(isSelected ? Color.blue : Color.clear, lineWidth: 2)
        )
    }
    
    private func formatCurrency(_ amount: Decimal, currency: Currency) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currency.rawValue
        return formatter.string(from: amount as NSDecimalNumber) ?? "$0.00"
    }
}

struct TransactionRowView: View {
    let transaction: Transaction
    
    var body: some View {
        HStack(spacing: 12) {
            Image(systemName: iconName)
                .font(.title3)
                .foregroundColor(iconColor)
                .frame(width: 40, height: 40)
                .background(iconColor.opacity(0.1))
                .cornerRadius(10)
            
            VStack(alignment: .leading, spacing: 4) {
                Text(transaction.description)
                    .font(.subheadline)
                    .fontWeight(.medium)
                    .lineLimit(1)
                HStack(spacing: 4) {
                    Text(transaction.type.rawValue.capitalized)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Text("•")
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Text(formatDate(transaction.timestamp))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 4) {
                Text("\(amountPrefix)\(formatAmount(transaction.amount))")
                    .font(.subheadline)
                    .fontWeight(.semibold)
                    .foregroundColor(amountColor)
                
                Text(transaction.status.rawValue.capitalized)
                    .font(.caption2)
                    .padding(.horizontal, 6)
                    .padding(.vertical, 2)
                    .background(statusColor.opacity(0.1))
                    .foregroundColor(statusColor)
                    .cornerRadius(4)
            }
        }
        .padding(.vertical, 8)
    }
    
    private var iconName: String {
        switch transaction.type {
        case .deposit: return "arrow.down.circle.fill"
        case .withdrawal: return "arrow.up.circle.fill"
        case .transfer: return "arrow.left.arrow.right.circle.fill"
        case .payment: return "creditcard.fill"
        }
    }
    
    private var iconColor: Color {
        switch transaction.type {
        case .deposit: return .green
        case .withdrawal: return .red
        case .transfer: return .blue
        case .payment: return .orange
        }
    }
    
    private var amountPrefix: String {
        switch transaction.type {
        case .deposit: return "+"
        case .withdrawal, .transfer, .payment: return "-"
        }
    }
    
    private var amountColor: Color {
        switch transaction.type {
        case .deposit: return .green
        case .withdrawal, .transfer, .payment: return .red
        }
    }
    
    private var statusColor: Color {
        switch transaction.status {
        case .completed: return .green
        case .pending: return .orange
        case .failed: return .red
        case .cancelled: return .gray
        }
    }
    
    private func formatAmount(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = transaction.currency.rawValue
        return formatter.string(from: amount as NSDecimalNumber) ?? "$0.00"
    }
    
    private func formatDate(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }
}

struct TransactionFormView: View {
    @ObservedObject var viewModel: AccountBalanceViewModel
    let transactionType: TransactionType
    @Environment(\.dismiss) private var dismiss
    
    @State private var amountString: String = ""
    @State private var description: String = ""
    @State private var selectedToAccountId: String = ""
    
    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("Transaction Details")) {
                    HStack {
                        Text("Type")
                        Spacer()
                        Text(transactionType.rawValue.capitalized)
                            .foregroundColor(.secondary)
                    }
                    
                    if let account = viewModel.selectedAccount {
                        HStack {
                            Text("From Account")
                            Spacer()
                            Text(account.maskedAccountNumber)
                                .foregroundColor(.secondary)
                        }
                        
                        HStack {
                            Text("Available Balance")
                            Spacer()
                            Text(formatCurrency(account.balance))
                                .foregroundColor(.secondary)
                        }
                    }
                }
                
                Section(header: Text("Amount")) {
                    TextField("Enter amount", text: $amountString)
                        .keyboardType(.decimalPad)
                }
                
                if transactionType == .transfer {
                    Section(header: Text("Transfer To")) {
                        Picker("Select Account", selection: $selectedToAccountId) {
                            Text("Select an account").tag("")
                            ForEach(viewModel.accounts.filter { $0.id != viewModel.selectedAccount?.id }) { account in
                                Text("\(account.accountHolderName) - \(account.maskedAccountNumber)")
                                    .tag(account.id)
                            }
                        }
                    }
                }
                
                Section(header: Text("Description")) {
                    TextField("Enter description", text: $description)
                }
                
                Section {
                    Button(action: submitTransaction) {
                        HStack {
                            Spacer()
                            Text("Submit \(transactionType.rawValue.capitalized)")
                                .fontWeight(.semibold)
                            Spacer()
                        }
                    }
                    .disabled(!isFormValid)
                }
            }
            .navigationTitle("New \(transactionType.rawValue.capitalized)")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
    
    private var isFormValid: Bool {
        guard let amount = Decimal(string: amountString), amount > 0 else { return false }
        if transactionType == .transfer && selectedToAccountId.isEmpty { return false }
        return !description.isEmpty
    }
    
    private func submitTransaction() {
        guard let amount = Decimal(string: amountString) else { return }
        
        switch transactionType {
        case .deposit:
            viewModel.deposit(amount: amount, description: description)
        case .withdrawal:
            viewModel.withdraw(amount: amount, description: description)
        case .transfer:
            viewModel.transfer(amount: amount, toAccountId: selectedToAccountId, description: description)
        case .payment:
            viewModel.withdraw(amount: amount, description: "Payment: \(description)")
        }
        
        dismiss()
    }
    
    private func formatCurrency(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: amount as NSDecimalNumber) ?? "$0.00"
    }
}

